'use client'
import { cn, useSignal, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import type { HTMLAttributes, ReactNode } from 'react'
import styles from './alert.module.css'

export interface AlertProps extends Omit<HTMLAttributes<HTMLDivElement>, 'title'> {
  variant?: 'default' | 'info' | 'success' | 'warning' | 'destructive'
  title?: string
  icon?: ReactNode
  dismissible?: boolean
  onDismiss?: () => void
  action?: { label: string; onClick: () => void }
}

const assertiveVariants = new Set(['warning', 'destructive'])

export function Alert({
  variant = 'default',
  title,
  icon,
  dismissible = false,
  onDismiss,
  action,
  className,
  children,
  ...props
}: AlertProps) {
  useSignals()
  const dismissed = useSignal(false)
  if (dismissed.value) return null

  return (
    <div
      role={assertiveVariants.has(variant) ? 'alert' : 'status'}
      data-variant={variant}
      className={cn(styles['alert'], className)}
      {...props}
    >
      {icon && (
        <span className={styles['icon']} aria-hidden="true">
          {icon}
        </span>
      )}
      <div className={styles['body']}>
        {title && <div className={styles['title']}>{title}</div>}
        {children && <div className={styles['content']}>{children}</div>}
        {action && (
          <button type="button" className={styles['action']} onClick={action.onClick}>
            {action.label}
          </button>
        )}
      </div>
      {dismissible && (
        <button
          type="button"
          className={styles['dismiss']}
          aria-label={t(builtin.alert.dismiss)}
          onClick={() => {
            dismissed.value = true
            onDismiss?.()
          }}
        >
          ✕
        </button>
      )}
    </div>
  )
}

@layer cascivo.component {
  .alert {
    display: flex;
    gap: var(--cascivo-space-3);
    padding: var(--cascivo-space-4);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-surface);
    background-color: var(--cascivo-color-surface);
    font-family: var(--cascivo-font-sans);
    color: var(--cascivo-color-text);

    &[data-variant='info'] {
      border-color: color-mix(in oklch, var(--cascivo-color-info) 35%, var(--cascivo-color-border));
      background: color-mix(in oklch, var(--cascivo-color-info) 5%, var(--cascivo-color-bg));
      color: var(--cascivo-color-info-content);
    }

    &[data-variant='info'] .icon,
    &[data-variant='info'] .title {
      color: var(--cascivo-color-info-foreground, var(--cascivo-color-info));
    }

    &[data-variant='success'] {
      border-color: color-mix(
        in oklch,
        var(--cascivo-color-success) 35%,
        var(--cascivo-color-border)
      );
      background: color-mix(in oklch, var(--cascivo-color-success) 5%, var(--cascivo-color-bg));
      color: var(--cascivo-color-success-content);
    }

    &[data-variant='success'] .icon,
    &[data-variant='success'] .title {
      color: var(--cascivo-color-success-foreground, var(--cascivo-color-success));
    }

    &[data-variant='warning'] {
      border-color: color-mix(
        in oklch,
        var(--cascivo-color-warning) 35%,
        var(--cascivo-color-border)
      );
      background: color-mix(in oklch, var(--cascivo-color-warning) 5%, var(--cascivo-color-bg));
      color: var(--cascivo-color-warning-content);
    }

    &[data-variant='warning'] .icon,
    &[data-variant='warning'] .title {
      color: var(--cascivo-color-warning-foreground, var(--cascivo-color-warning));
    }

    &[data-variant='destructive'] {
      border-color: color-mix(
        in oklch,
        var(--cascivo-color-destructive) 35%,
        var(--cascivo-color-border)
      );
      background: color-mix(in oklch, var(--cascivo-color-destructive) 5%, var(--cascivo-color-bg));
      color: var(--cascivo-color-destructive-content);
    }

    &[data-variant='destructive'] .icon,
    &[data-variant='destructive'] .title {
      color: var(--cascivo-color-destructive-foreground, var(--cascivo-color-destructive));
    }
  }

  .icon {
    display: flex;
    flex-shrink: 0;
    align-items: center;
    line-height: 1;
    margin-block-start: 0.125rem;

    .alert[data-variant='info'] & {
      color: var(--cascivo-color-info-foreground, var(--cascivo-color-info));
    }
    .alert[data-variant='success'] & {
      color: var(--cascivo-color-success-foreground, var(--cascivo-color-success));
    }
    .alert[data-variant='warning'] & {
      color: var(--cascivo-color-warning-foreground, var(--cascivo-color-warning));
    }
    .alert[data-variant='destructive'] & {
      color: var(--cascivo-color-destructive-foreground, var(--cascivo-color-destructive));
    }
  }

  .body {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
    flex: 1;
    min-inline-size: 0;
  }

  .title {
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-semibold);
    line-height: var(--cascivo-leading-snug);
  }

  .content {
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
    line-height: var(--cascivo-leading-normal);
  }

  .action {
    align-self: flex-start;
    margin-block-start: var(--cascivo-space-1);
    padding-block: var(--cascivo-space-1);
    padding-inline: var(--cascivo-space-2);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    line-height: var(--cascivo-leading-none);
    color: var(--cascivo-color-text);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    transition: background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    .alert[data-variant='info'] & {
      color: var(--cascivo-color-info-foreground, var(--cascivo-color-info));
    }
    .alert[data-variant='success'] & {
      color: var(--cascivo-color-success-foreground, var(--cascivo-color-success));
    }
    .alert[data-variant='warning'] & {
      color: var(--cascivo-color-warning-foreground, var(--cascivo-color-warning));
    }
    .alert[data-variant='destructive'] & {
      color: var(--cascivo-color-destructive-foreground, var(--cascivo-color-destructive));
    }
  }

  .dismiss {
    display: flex;
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    inline-size: 1.5rem;
    block-size: 1.5rem;
    padding: 0;
    font-size: var(--cascivo-text-xs);
    color: var(--cascivo-color-text-muted);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    transition:
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }
  }
}

@media (forced-colors: active) {
  .alert {
    border: 1px solid CanvasText;
  }

  .alert[data-variant='info'],
  .alert[data-variant='success'],
  .alert[data-variant='warning'],
  .alert[data-variant='destructive'] {
    border-width: 2px;
  }

  .dismiss:focus-visible {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }
}

@media (prefers-contrast: more) {
  .alert {
    border-width: 2px;
  }

  .alert[data-variant='info'],
  .alert[data-variant='success'],
  .alert[data-variant='warning'],
  .alert[data-variant='destructive'] {
    border-width: 2px;
  }
}
